import sys
class TreeNode:
    def __init__(self, x):
        self.val = x
        self.left = None
        self.right = None

class Solution:
    def lowestCommonAncestor(self, root: TreeNode, p: TreeNode, q: TreeNode) -> TreeNode:
        if not root:
            return None
        if root == p or root == q:
            return root
        left = self.lowestCommonAncestor(root.left, p, q)
        right = self.lowestCommonAncestor(root.right, p, q)
        if left and right:
            return root
        return left if left else right

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        root = TreeNode(int(next(it)))
        node_dict = {root.val: root}
        stack = [root]
        for _ in range(n - 1):
            val = int(next(it))
            node = TreeNode(val)
            node_dict[val] = node
            if stack:
                parent = stack[-1]
                if not parent.left:
                    parent.left = node
                else:
                    parent.right = node
            stack.append(node)
            if stack[-1].left and stack[-1].right:
                stack.pop()
        k = int(next(it))
        p_val = int(next(it))
        q_val = int(next(it))
        p = node_dict[p_val]
        q = node_dict[q_val]
        sol = Solution()
        ans = sol.lowestCommonAncestor(root, p, q)
        print(ans.val)
    except StopIteration:
        sys.exit(0)

