#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    TreeNode* lowestCommonAncestor(TreeNode* root, TreeNode* p, TreeNode* q) {
        if (!root) return NULL;
        if (root == p || root == q) return root;
        TreeNode* left = lowestCommonAncestor(root->left, p, q);
        TreeNode* right = lowestCommonAncestor(root->right, p, q);
        if (left && right) return root;
        return left ? left : right;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    TreeNode* root = new TreeNode(0);
    unordered_map<int, TreeNode*> node_dict;
    node_dict[0] = root;
    stack<TreeNode*> stack;
    stack.push(root);
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        TreeNode* node = new TreeNode(val);
        node_dict[val] = node;
        if (!stack.empty()) {
            TreeNode* parent = stack.top();
            if (!parent->left) {
                parent->left = node;
            } else {
                parent->right = node;
            }
        }
        stack.push(node);
        if (stack.top()->left && stack.top()->right) {
            stack.pop();
        }
    }
    int k;
    cin >> k;
    int p_val, q_val;
    cin >> p_val >> q_val;
    Solution sol;
    TreeNode* p = node_dict[p_val];
    TreeNode* q = node_dict[q_val];
    TreeNode* ans = sol.lowestCommonAncestor(root, p, q);
    cout << ans->val << '\n';
    return 0;
}
